mapper.select:
SELECT tc.ticket_id, tc.fault_time, CASE WHEN tc.status = 'AUTO_FIN' THEN tc.ticket_update_time ELSE sop.handling_fin_time END AS handling_fin_time, tc.ticket_type, tc.ticket_rca_result_dtl_code, tc.status , ta.root_cause_sysnamea, ta.root_cause_porta, ta.root_cause_sysnamez, ta.root_cause_portz, tc.parent_ticket_id FROM rca.tb_rca_ticket_current tc INNER JOIN rca.tb_rca_ticket_al_current ta ON tc.ticket_id = ta.ticket_id LEFT OUTER JOIN nia.tb_sop sop ON tc.ticket_id = sop.ticket_id WHERE 1=1
AND tc.ticket_id = #{TICKET_ID}
AND tc.ticket_type = #{TICKET_TYPE}
AND tc.fault_time > rca.fc_get_minus_day(7)
AND tc.fault_time >= #{OCCUR_START_DATE}::timestamp
AND tc.fault_time <= #{OCCUR_END_DATE}::timestamp
AND CASE WHEN tc.status = 'AUTO_FIN' THEN tc.ticket_update_time ELSE sop.handling_fin_time END >= #{DEADLINE_START_DATE}::timestamp
AND CASE WHEN tc.status = 'AUTO_FIN' THEN tc.ticket_update_time ELSE sop.handling_fin_time END <= #{DEADLINE_END_DATE}::timestamp
ORDER BY tc.ticket_id DESC
OFFSET #{OFFSET} LIMIT #{LIMIT}
LIMIT #{LIMIT}

SELECT sysnamea, sysnamez
FROM rca.tb_rca_ticket_cable_mst
WHERE ticket_id = #{TICKET_ID}

SELECT src_country_code , scc.country_name AS src_country_name , dst_country_code , dcc.country_name AS dst_country_name , packet_bytes, rank_order FROM ( SELECT src_country_code , dst_country_code , SUM(packet_bytes) packet_bytes , row_number () over (ORDER BY case when src_country_code is null and src_country_code is null then 0 else 2 end desc, SUM(packet_bytes) DESC) rank_order FROM gather.tb_mdb_sflow_traffic_day dt WHERE 1=1 and dt.collect_timestamp > rca.fc_get_minus_day(5) GROUP BY src_country_code , dst_country_code ) dt INNER JOIN gather.tb_country_code scc ON scc.iso_alpha2 = dt.src_country_code INNER JOIN gather.tb_country_code dcc ON dcc.iso_alpha2 = dt.dst_country_code WHERE 1=1
AND src_country_code = #{SRC_COUNTRY_CODE}
AND dst_country_code = #{DST_COUNTRY_CODE}
AND rank_order < 101
AND rank_order <= #{TOP_N}

SELECT src_ip, src_nren_id, src_nren_name, src_country_code, dst_ip, dst_nren_id, dst_nren_name, dst_country_code, packet_bytes, row_number FROM ( SELECT src_ip, src_nren_id, src_nren_name , src_country_code, dst_ip, dst_nren_id, dst_nren_name , dst_country_code , SUM(packet_bytes) packet_bytes , row_number() over (ORDER BY case when src_nren_id is null and dst_nren_id is null then 0 else 2 end desc, SUM(packet_bytes) DESC) row_number FROM gather.tb_mdb_sflow_traffic_day dt WHERE 1=1 and dt.collect_timestamp > rca.fc_get_minus_day(5)
AND src_nren_id = #{SRC_AGENCY_ID}
AND dst_nren_id = #{DST_AGENCY_ID}
AND src_ip = #{SRC_AGENCY_IP}
AND dst_ip = #{DST_AGENCY_IP}
GROUP BY src_ip, src_nren_id, src_nren_name , src_country_code , dst_ip, dst_nren_id, dst_nren_name , dst_country_code ) dt WHERE 1=1
AND row_number < 101
AND row_number <= #{TOP_N}

SELECT src_protocol, src_port, dst_protocol, dst_port, packet_bytes, rank_order FROM ( SELECT src_protocol, src_port, dst_protocol, dst_port, SUM(packet_bytes) packet_bytes , row_number() over (ORDER BY CASE WHEN src_protocol IS NULL AND dst_protocol IS NULL THEN 0 ELSE 2 END DESC, SUM(packet_bytes) DESC) rank_order FROM gather.tb_mdb_sflow_traffic_day dt WHERE 1=1 and dt.collect_timestamp > rca.fc_get_minus_day(5)
AND src_port = #{SRC_APPLICATION_CODE}
AND src_port like '%' || #{SRC_PORT} || '%'
AND dst_port = #{DST_APPLICATION_CODE}
AND dst_port like '%' || #{DST_PORT} || '%'
GROUP BY src_protocol, src_port , dst_protocol, dst_port ) dt WHERE 1=1
AND rank_order < 101
AND rank_order <= #{TOP_N}

SELECT * FROM nia.tb_ipsdn_handling_hist WHERE 1=1
AND handling_time > #{START_DATE}::timestamp
AND handling_time <= #{END_DATE}::timestamp
ORDER BY handling_time DESC
OFFSET #{OFFSET} LIMIT #{LIMIT}
LIMIT #{LIMIT}

WITH TRAFFIC_DATA AS ( SELECT NM.NODE_NUM, NM.NODE_NM, N.ID AS SDN_NODE_ID, PM.IF_NUM, I.ID AS SDN_IF_ID, I.IF_NAME, LT.TX_BIT_RATE, LT.RX_BIT_RATE, LT.TX_PKT_RATE, LT.RX_PKT_RATE, LT.MEASURED_DATETIME FROM IP_SDN.TB_LINK_TRAFFIC LT INNER JOIN IP_SDN.TB_INTERFACE I ON LT.IF_ID = I.ID INNER JOIN RESOURCE.TB_PORT_MST PM ON PM.IF_ID = LOWER(I.IF_NAME) INNER JOIN IP_SDN.TB_NODE N ON I.NODE_ID = N.ID INNER JOIN RESOURCE.TB_NODE_MST NM ON N.ID = NM.IP_SDN_ID::INT WHERE PM.NODE_NUM = NM.NODE_NUM
AND LT.MEASURED_DATETIME BETWEEN NOW()::timestamp - interval '10 min' AND NOW()::timestamp
AND LT.MEASURED_DATETIME > #{START_DATE}::timestamp
AND LT.MEASURED_DATETIME <= #{END_DATE}::timestamp
AND nm.NODE_NM = #{EQUIPMENT}
AND I.IF_NAME = #{INTERFACE}
) SELECT T.NODE_NUM, T.NODE_NM AS NODE_NAME, T.SDN_NODE_ID, T.IF_NUM, T.SDN_IF_ID, T.IF_NAME, T.DIRECTION, T.RX_BIT_RATE, T.RX_PKT_RATE, T.TX_BIT_RATE, T.TX_PKT_RATE, T.MEASURED_DATETIME , CASE WHEN (SELECT 1 FROM RCA.TB_ANOMALOUS_1MI_TRAFFIC WHERE STRRESID = T.NODE_NUM AND STRIFID = T.IF_NUM AND MEASURED_DATETIME = T.MEASURED_DATETIME
AND MEASURED_DATETIME BETWEEN NOW()::timestamp - interval '10 min' AND NOW()::timestamp
AND MEASURED_DATETIME > #{START_DATE}::timestamp
AND MEASURED_DATETIME <= #{END_DATE}::timestamp
) =1 THEN TRUE ELSE FALSE END AI_RESULT FROM ( SELECT NODE_NUM, NODE_NM, SDN_NODE_ID, IF_NUM, SDN_IF_ID, IF_NAME, 'IN' AS DIRECTION, RX_BIT_RATE, RX_PKT_RATE, 0 AS TX_BIT_RATE, 0 AS TX_PKT_RATE, MEASURED_DATETIME FROM TRAFFIC_DATA UNION ALL SELECT NODE_NUM, NODE_NM, SDN_NODE_ID, IF_NUM, SDN_IF_ID, IF_NAME, 'OUT' AS DIRECTION, 0 AS RX_BIT_RATE, 0 AS RX_PKT_RATE, TX_BIT_RATE, TX_PKT_RATE, MEASURED_DATETIME FROM TRAFFIC_DATA ) T ORDER BY MEASURED_DATETIME DESC
OFFSET #{OFFSET} LIMIT #{LIMIT}
LIMIT #{LIMIT}

SELECT nm.node_num AS node_num, nm.node_nm AS node_name, n.id AS sdn_node_id, pm.if_num AS if_num, i.if_name AS if_name, lt.tx_bit_rate AS tx_bit_rate, lt.rx_bit_rate AS rx_bit_rate, lt.tx_pkt_rate AS tx_pkt_rate, lt.rx_pkt_rate AS rx_pkt_rate, lt.measured_datetime AS measured_datetime FROM ip_sdn.tb_link_traffic lt INNER JOIN ip_sdn.tb_interface i ON lt.if_id = i.id INNER JOIN resource.tb_port_mst pm ON pm.if_id = lower(i.if_name) INNER JOIN ip_sdn.tb_node n ON i.node_id = n.id INNER JOIN resource.tb_node_mst nm ON n.id = nm.ip_sdn_id::INT WHERE pm.node_num = nm.node_num
AND lt.MEASURED_DATETIME > #{START_DATE}::timestamp
AND lt.MEASURED_DATETIME <= #{END_DATE}::timestamp
AND nm.NODE_NM = #{EQUIPMENT}
AND i.IF_NAME = #{INTERFACE}
ORDER BY MEASURED_DATETIME DESC
OFFSET #{OFFSET} LIMIT #{LIMIT}
LIMIT #{LIMIT}

SELECT a.node_num AS node_num, a.sdn_node_id AS sdn_node_id, a.node_nm AS node_nm, trunc(a.cpu_usage::numeric,3) * 100 as cpu_usage, trunc(a.mem_usage::numeric,3) * 100 as mem_usage, a.measured_datetime AS measured_datetime, CASE WHEN tn.strresid IS NOT NULL THEN true ELSE false END AS ai_result FROM ( SELECT nm.node_num, n.id AS sdn_node_id, nm.node_nm, nf.cpu_usage, nf.mem_usage, nf.measured_datetime FROM ip_sdn.tb_nodefactor nf INNER JOIN ip_sdn.tb_node n ON nf.node_id = n.id INNER JOIN resource.tb_node_mst nm ON n.id = nm.ip_sdn_id::INT WHERE 1=1
AND nf.MEASURED_DATETIME BETWEEN NOW()::timestamp - interval '30 min' AND NOW()::timestamp
AND nf.MEASURED_DATETIME > #{START_DATE}::timestamp
AND nf.MEASURED_DATETIME <= #{END_DATE}::timestamp
AND nm.NODE_NM = #{EQUIPMENT}
AND nf.cpu_usage::text LIKE #{CPU} || '%'
AND nf.mem_usage::text LIKE #{MEM} || '%'
ORDER BY MEASURED_DATETIME DESC
OFFSET #{OFFSET} LIMIT #{LIMIT}
LIMIT #{LIMIT}
) a LEFT OUTER JOIN rca.tb_nodefactor tn ON tn.strresid = a.node_num AND tn.measured_datetime = a.measured_datetime

SELECT SUM(trans_perf_cnt) AS trans_perf_cnt, SUM(trans_alarm_cnt) AS trans_alarm_cnt, SUM(ip_resource_cnt) AS ip_resource_cnt, SUM(ip_alarm_cnt) AS ip_alarm_cnt, SUM(ip_perf_cnt) AS ip_perf_cnt, SUM(ip_sflow_cnt) AS ip_sflow_cnt, SUM(ticket_rt_cnt) AS ticket_rt_cnt, SUM(ticket_att_cnt) AS ticket_att_cnt, SUM(ticket_ntt_cnt) AS ticket_ntt_cnt, SUM(ticket_pf_cnt) AS ticket_pf_cnt, SUM(link_total_resource_cnt) AS link_total_resource_cnt, SUM(link_total_alarm_cnt) AS link_total_alarm_cnt, SUM(link_ip_perf_cnt) AS link_ip_perf_cnt, SUM(link_trans_perf_cnt) AS link_trans_perf_cnt FROM nia.tb_opsts WHERE 1=1
AND opsts_time >= #{START_DATE}
AND opsts_time <= #{END_DATE}
AND opsts_time = #{MONTH}
AND opsts_gb = 'DAY'
AND opsts_gb = #{DATA_TYPE}

SELECT T.EQUIPTYPE, COUNT(T.EQUIPTYPE) AS equip_count FROM rca.tb_alarm_cur_mst T
T.CLUSTERNO = #{CLUSTERNO}
GROUP BY T.EQUIPTYPE

