WITH UPSERT AS ( UPDATE nia.tb_tsdn_service_response_info
service_id = #{SERVICE_ID}, reserved_num = #{RESERVED_NUM}, ticket_id = #{TICKET_ID}::VARCHAR, sop_id = #{SOP_ID}
WHERE ticket_id = #{TICKET_ID}::VARCHAR RETURNING * ) INSERT INTO rca.tb_tsdn_service_response_info ( service_id, reserved_num, ticket_id, sop_id ) SELECT #{SERVICE_ID}::VARCHAR, #{RESERVED_NUM}, #{TICKET_ID}::VARCHAR, #{SOP_ID} WHERE NOT EXISTS(SELECT * FROM UPSERT)

mapper.select:
SELECT list.collect_time::TIMESTAMP , cp.inttimestamp , node_id , if_id , node_num , if_num , intmin , COALESCE(fltbpsin, 0) as fltbpsin /* 입력 bps */ , COALESCE(fltbpsout, 0) as fltbpsout /* 출력 bps */ , COALESCE(fltppsin, 0) as fltppsin /* 입력 pps */ , COALESCE(fltppsout, 0) as fltppsout /* 출력 pps */ , COALESCE(fltusage, 0) as fltusage/* 사용율 */ FROM ( SELECT collect_time, node_id, if_id, node_num, if_num FROM ( SELECT to_timestamp(floor((extract('epoch' from (timeinterval - (interval '9 hours') + (interval '5' minute))) / 300)) * 300) collect_time FROM generate_series(date_trunc('min',#{FAULT_TIME}::timestamp - interval '1 hours'),date_trunc('min',#{FAULT_TIME}::timestamp + interval '1 hours' - interval '5 min'), '5 min'::interval) timeinterval ) tl INNER JOIN ( SELECT pm.node_id , pm.if_id, nm.node_num , pm.if_num FROM resource.tb_node_mst nm INNER JOIN resource.tb_port_mst pm on nm.node_id =pm.node_id ) il on 1=1 WHERE 1=1
and il.node_id = #{NODE}
and il.if_id like '%' || #{INTERFACE}
) list left outer join ip_yd.xe_cvnms_perf_if cp on to_timestamp(floor((extract('epoch' from (to_timestamp(cp.inttimestamp) + (interval '5' minute))) / 300)) * 300) = list.collect_time and list.node_num = cp.strresid and list.if_num= cp.strifid

select row_number() over (ORDER BY node_num) rnum, node.* from ( select tnm.node_num, tnm.node_id, tnm.node_nm, tnm.model_num, tnm.model_id, code.code_nm, tnm.ip_addr, tnm.mac_addr, tnm.admin_yn, tnm.primary_gb, tnm.snmp_ver, tnm.snmp_community, tnm.snmp_port, tnm.latitude, tnm.longitude, tnm.netconf_port, tnm.netconf_id, tnm.netconf_pw, tnm.netconf_type, tnm.node_division, tnm.vendor, tnm.sflow_ip, to_char(tnm.chng_datetime, 'YYYY-MM-DD HH:MI:SS') as chng_datetime, count(1) over () as "NodeTotalCount" from resource.tb_node_mst tnm LEFT OUTER JOIN resource.tb_code code on (tnm.model_id = code.code_id) where 1=1
AND tnm.NODE_NM like '%' || #{NODE_NM} || '%'
AND code.CODE_NM like '%' || #{MODEL_ID} || '%'
AND tnm.IP_ADDR like '%' || #{IP_ADDR} || '%'
AND tnm.ADMIN_YN like '%' || #{ADMIN_YN} || '%'
AND tnm.CHNG_DATETIME BETWEEN #{START_DATE} ::timestamp and #{END_DATE}::timestamp
ORDER BY chng_datetime ASC
OFFSET #{OFFSET}
LIMIT #{LIMIT}
) AS node ORDER BY node_num

