where  node_num = #{NODE_NUM}
and node_id = #{NODE_ID}

delete from resource.tb_port_mst
where node_num = #{NODE_NUM}
and if_nm = #{IF_NM}

mapper.select:
select row_number() over () rnum , * , count(1) over () as "LinkTotalCount" from ( select distinct bl.src_node_num , bl.src_node_id , bl.src_if_num , bl.src_if_id , sp.if_nm as src_if_name , bl.src_ip_addr , bl.src_mac_addr , bl.dest_node_num , bl.dest_node_id , bl.dest_if_num , bl.dest_if_id , dp.if_nm as dest_if_name , bl.dest_ip_addr , bl.dest_mac_addr , bl.prefix , bl.bandwidth , bl.circuit_num , bl.link_type , bl.vlan "VLAN" , bl.tag "TAG" , bl.link_desc , TO_CHAR(bl.chng_datetime, 'YYYY-MM-DD HH24:mi:SS') as chng_datetime from resource.tb_backbone_link bl left outer join resource.tb_port_mst sp on sp.node_id = bl.src_node_id and sp.if_id = bl.src_if_id left outer join resource.tb_port_mst dp on dp.node_id = bl.dest_node_id and dp.if_id = bl.dest_if_id where 1=1 AND bl.src_node_id LIKE '%' || #{SRC_NODE_ID} || '%'
AND bl.src_if_id LIKE '%' || #{SRC_IF_ID} || '%'
AND bl.dest_node_id LIKE '%' || #{DEST_NODE_ID} || '%'
AND bl.dest_if_id LIKE '%' || #{DEST_IF_ID} || '%'
AND bl.link_desc LIKE '%' || #{LINK_DESC} || '%'
) AS link
OFFSET #{OFFSET}
LIMIT #{LIMIT}

