where src_node_id = #{SRC_NODE_ID}
  and src_if_id = #{SRC_IF_ID}
  and dest_node_id = #{DEST_NODE_ID}
  and dest_if_id = #{DEST_IF_ID}

mapper.update:
update resource.tb_backbone_link set
    bandwidth = #{BANDWIDTH}
    ,link_desc = #{LINK_DESC}
    , vlan = #{VLAN}
    , tag = #{TAG}
    , chng_datetime = now()
where src_node_id = #{SRC_NODE_ID}
  and src_if_id = #{SRC_IF_ID}
  and dest_node_id = #{DEST_NODE_ID}
  and dest_if_id = #{DEST_IF_ID}

