mapper.select:
SELECT sysDialog.alarmno, sysDialog.alarmtime, sysDialog.node_num, sysDialog.node_nm, sysDialog.alarmmsg, sysDialog.alarmlvl, sysDialog.etc, sysDialog.rule_id, sysDialog.alarmloc, CASE WHEN sysDialog.status = 'INIT' THEN '발생' WHEN sysDialog.status = 'FIN' THEN '마감' WHEN sysDialog.status = 'AUTO_FIN' THEN '자동 마감' ELSE '-' END AS status FROM rca.tb_syslog_alarm_mst sysDialog
sysDialog.alarmtime BETWEEN NOW()::timestamp - interval '30 day' AND NOW()::timestamp
AND sysDialog.alarmtime > #{START_DATE}::timestamp
AND sysDialog.alarmtime <= #{END_DATE}::timestamp
AND sysDialog.alarmno = #{ALARMNO}
AND sysDialog.node_nm = #{EQUIPMENT}
AND sysDialog.node_num = #{NODENUM}
AND UPPER(sysDialog.alarmmsg) LIKE '%' || UPPER(#{ALARMMSG}) || '%'
ORDER BY sysDialog.alarmno DESC
OFFSET #{OFFSET} LIMIT #{LIMIT}
LIMIT #{LIMIT}

mapper.update:
UPDATE NIA.TB_SYSLOG_SOP SET STATUS = #{STATUS},
FAULT_CLASSIFY = #{FAULT_CLASSIFY},
FAULT_TYPE = #{FAULT_TYPE},
FAULT_DETAIL_CONTENT = #{FAULT_DETAIL_CONTENT},
ETC_CONTENT = #{ETC_CONTENT}
WHERE ALARMNO = #{ALARMNO}

mapper.insert:
INSERT INTO gather.tb_syslog_rule_mst ( syslog_rule_id, syslog_rule_nm, node_type, priority_order, alarm_severity, occur_str1, occur_str2, occur_str3, occur_except_str1, occur_except_str2, occur_except_str3, use_yn ) VALUES ( NEXTVAL('gather.seq_syslog_rule') ,#{SYSLOG_RULE_NM} ,'*' ,1 ,7 ,#{OCCUR_STR1}
,#{OCCUR_STR2}
,#{OCCUR_STR3}
,#{OCCUR_EXCEPT_STR1}
,#{OCCUR_EXCEPT_STR2}
,#{OCCUR_EXCEPT_STR3}
,'Y' )

mapper.select:
SELECT syslog.alarmno, syslog.node_nm, syslog.node_num, syslog.alarmloc, syslog.alarmtime, syslog.alarmmsg, syslog.etc, sop.proc_status, sop.fault_classify, sop.fault_type, sop.fault_detail_content, sop.etc_content, sop.alarm_occur_time, sop.handling_fin_time, sop.handling_fin_user, sop.status, COUNT(1) over () totalCount FROM nia.tb_syslog_sop sop LEFT OUTER JOIN rca.tb_syslog_alarm_mst syslog ON sop.alarmno = syslog.alarmno WHERE 1=1
AND syslog.node_nm = #{EQUIPMENT}
AND syslog.alarmloc = #{IFNAME}
AND syslog.alarmtime > now() - INTERVAL '1' MONTH ORDER BY syslog.alarmtime DESC

SELECT sop.alarmno, syslog.node_nm, syslog.alarmloc, syslog.etc, sop.proc_status, sop.fault_classify, sop.fault_type, sop.fault_detail_content, sop.etc_content, sop.alarm_occur_time, sop.handling_fin_time, sop.handling_fin_user, CASE WHEN sop.status = 'INIT' THEN '발생' WHEN sop.status = 'FIN' THEN '마감' WHEN sop.status = 'AUTO_FIN' THEN '자동 마감' ELSE '-' END AS status, COUNT(1) over () totalCount FROM nia.tb_syslog_sop sop INNER JOIN rca.tb_syslog_alarm_mst syslog ON sop.alarmno = syslog.alarmno WHERE 1=1
AND syslog.node_nm = #{EQUIPMENT}
AND syslog.alarmloc = #{IFNAME}
AND sop.status = #{STATUS}
AND sop.alarm_occur_time >= #{START_DATE}::TIMESTAMP
AND sop.handling_fin_time <= #{END_DATE}::TIMESTAMP
AND sop.alarmno = #{ALARMNO}
AND sop.handling_fin_time > now() - INTERVAL '1' MONTH order by sop.alarm_occur_time desc
OFFSET #{OFFSET}
LIMIT #{LIMIT}

SELECT ROW_NUMBER() OVER (ORDER BY occur_time DESC) AS row_num, CASE WHEN tatpdt.self_process_type = 'A' THEN '이상트래픽' WHEN tatpdt.self_process_type = 'N' THEN '유해트래픽' WHEN tatpdt.self_process_type = 'S' THEN 'SYSLOG' WHEN tatpdt.self_process_type = 'F' THEN '비장애' ELSE '' END AS selfProcessType, tatpdt.self_process_group, tatpdt.self_process_type, CASE WHEN clos_type = 'A' THEN '자동' ELSE '수동' END AS clos_type, tatpdt.feedback_msg, TO_CHAR(tatpdt.occur_time, 'YYYY-MM-DD HH24:MI') AS occur_time, tatpdt.feedback_time, tatpdt.ticket_id, tatpdt.ticket_type, tatpdt.self_process_no, tatpdt.alarmno, CASE WHEN clos_status = 'Y' THEN '마감' ELSE '발생' END AS closStatus, tatpdt.clos_status, TO_CHAR(tatpdt.clos_time, 'YYYY-MM-DD HH24:MI') AS clos_time, tsam.node_nm, tsam.alarmloc, ts.fault_detail_content as ticket_fault_detail_content, tss.fault_detail_content as syslog_fault_detail_content, trtc.fault_time, trtc.status FROM nia.tb_auto_treat_process_dtl tatpdt LEFT JOIN rca.tb_syslog_alarm_mst tsam ON tatpdt.alarmno = tsam.alarmno LEFT JOIN nia.tb_sop ts ON tatpdt.ticket_id = ts.ticket_id LEFT JOIN nia.tb_syslog_sop tss ON tatpdt.alarmno = tss.alarmno LEFT JOIN rca.tb_rca_ticket_current trtc ON tatpdt.ticket_id = trtc.ticket_id WHERE 1=1
AND tatpdt.occur_time >= #{DATETIME}::TIMESTAMP AND tatpdt.occur_time < #{DATETIME}::TIMESTAMP + INTERVAL '1 hour'
AND tatpdt.occur_time >= #{DATETIME}::TIMESTAMP AND tatpdt.occur_time < #{DATETIME}::TIMESTAMP + INTERVAL '1 day'
AND DATE_TRUNC('MONTH', tatpdt.occur_time) = TO_TIMESTAMP(CONCAT(#{DATETIME}, '-01'), 'YYYY-MM-DD')
AND tatpdt.self_process_group IN ('ST')
